use foundry_pi_roman_numeral::{from_roman, to_roman, RomanError};

const GOLDEN_VECTORS: &[(u16, &str)] = &[
    (1, "I"),
    (4, "IV"),
    (9, "IX"),
    (14, "XIV"),
    (40, "XL"),
    (44, "XLIV"),
    (49, "XLIX"),
