    assert_eq!(to_roman(4000), Err(RomanError::OutOfRange));
}

#[test]
fn from_roman_rejects_empty_input() {
    assert_eq!(from_roman(""), Err(RomanError::Empty));
}

#[test]
fn from_roman_rejects_required_non_canonical_inputs() {
    let invalid_cases = ["IIII", "VV", "IC", "IL", "XM", "MCMC", "VX"];

    for roman in invalid_cases {
        assert_eq!(
            from_roman(roman),
            Err(RomanError::NonCanonical),
            "{roman:?} uses Roman symbols but is not canonical"
        );
    }
}

#[test]
fn from_roman_rejects_additional_plausible_non_canonical_inputs() {
    let invalid_cases = [
        "IIV",   // repeated one before five instead of III/IV
        "IIX",   // repeated one before ten instead of VIII/IX
        "XXL",   // repeated ten before fifty
        "XXC",   // repeated ten before hundred
        "XD",    // ten cannot subtract from five hundred
        "LC",    // fifty cannot subtract
        "DM",    // five hundred cannot subtract
        "CMM",   // duplicate subtractive hundreds
        "CMCM",  // repeated 900 group
        "IVI",   // canonical five is V, not IVI
        "IXI",   // canonical ten is X, not IXI
    ];

    for roman in invalid_cases {
        assert_eq!(
            from_roman(roman),
            Err(RomanError::NonCanonical),
            "{roman:?} should be rejected instead of normalized"
        );
    }
}

#[test]
fn from_roman_rejects_lowercase_and_non_roman_characters() {
