        ("IIII", 4_u16, "IV"),
        ("VIIII", 9, "IX"),
        ("XXXX", 40, "XL"),
        ("LXXXX", 90, "XC"),
        ("CCCC", 400, "CD"),
        ("DCCCC", 900, "CM"),
        ("MCMXLIIII", 1944, "MCMXLIV"),
    ];

    for (input, value, canonical) in equivalent_but_noncanonical {
        assert_eq!(to_roman(value), Ok(canonical.to_string()));
        assert_eq!(
            from_roman(input),
            Err(RomanError::NonCanonical),
            "{input:?} represents {value} but must be rejected in favor of {canonical:?}"
        );
    }
}

